class Admin_Model_CategoryMeta extends Admin_Model_Base_CategoryMeta
{

    public static function getCategoryMetasByCategoryID(int $ID): array {
        return Doctrine_Query::create()
            ->addSelect('cm.ID as id, cm.Value as value, cm.Code as code, cm.Category_ID as category_id')
            ->from('Admin_Model_CategoryMeta cm')
            ->where('cm.Category_ID = ?', $ID)
            ->execute([], Doctrine_Core::HYDRATE_ARRAY);
    }

    public static function deleteCategoryMetasByCategoryID(int $ID) {
        Doctrine_Query::create()
            ->delete('Admin_Model_CategoryMeta cm')
            ->where('cm.Category_ID = ?', $ID)
            ->execute();
    }

    public static function getCategoryMetaByCode(int $categoryID, string $code) {
        return Doctrine_Query::create()
            ->addSelect('cm.ID as id, cm.Value as value, cm.Code as code, cm.Category_ID as category_id')
            ->from('Admin_Model_CategoryMeta cm')
            ->where('cm.Code = ?', $code)
            ->andWhere('cm.Category_ID = ?', $categoryID)
            ->fetchOne();
    }
}